SELECT COUNT(*) AS QTDE_PRODUCOES FROM LATTES_P_PRODBIB LPB JOIN LATTES_PRODBIB PB ON PB.PK = LPB.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPB.FK_SIAPE WHERE LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%jatai%') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%letras%') AND LOWER(PB.TIPO) = LOWER('capitulo de livro') AND PB.ANO = '2020' AND S.GENERO = 'FEMININO'